export function getCommonUnits(): string[] {
	return Object.keys(allUnits).filter(name => allUnits[name].Faction_Name === 'Common Unit');
}

export function getFactionUnits(): string[] {
	return Object.keys(allUnits).filter(name => allUnits[name].Faction_Name !== 'Common Unit');
}

export function getAllUnitNames(): string[] {
	return Object.keys(allUnits);
}

export function getFactions(): string[] {
	const factions = new Set(Object.values(allUnits).map(u => u.Faction_Name));
	factions.delete('Common Unit');
	return ['Common Unit', ...Array.from(factions).sort()];
}
